import sqlite3

# Initialize database connection
conn = sqlite3.connect('access_control.db')
cursor = conn.cursor()

# Create table if not exists
cursor.execute('''
CREATE TABLE IF NOT EXISTS permissions (
    user_id TEXT,
    file_path TEXT,
    read_permission BOOLEAN,
    PRIMARY KEY (user_id, file_path)
)
''')

def check_and_read_file(user_id, file_path):
    # Check permission in a transaction to avoid race conditions
    with conn:
        cursor.execute('SELECT read_permission FROM permissions WHERE user_id = ? AND file_path = ?', (user_id, file_path))
        result = cursor.fetchone()
        
        if result and result[0]:
            with open(file_path, 'r') as file:
                return file.read()
        else:
            raise PermissionError("User does not have permission to read the file.")

# Example usage
try:
    content = check_and_read_file('user123', '/path/to/file.txt')
    print(content)
except PermissionError as e:
    print(e)

# Close database connection
conn.close()